<template>
  <view class="test-container">
    <view class="test-header">
      <text class="test-title">购买按钮跳转测试</text>
    </view>
    
    <view class="test-section">
      <text class="section-title">测试商品列表</text>
      <view class="test-products">
        <view 
          v-for="(product, index) in testProducts" 
          :key="index"
          class="test-product-card"
          @click="goToProductDetail(product)"
        >
          <image :src="product.imageUrl" class="test-product-image" />
          <view class="test-product-info">
            <text class="test-product-name">{{ product.name }}</text>
            <text class="test-product-price">¥{{ product.price }}</text>
            <view class="test-buy-btn" @click.stop="addToCart(product)">
              购买
            </view>
          </view>
        </view>
      </view>
    </view>
    
    <view class="test-section">
      <text class="section-title">跳转日志</text>
      <view class="log-container">
        <text v-for="(log, index) in logs" :key="index" class="log-item">
          {{ log }}
        </text>
      </view>
    </view>
  </view>
</template>

<script setup>
import { ref } from 'vue';

const logs = ref([]);
const testProducts = ref([
  {
    id: 1,
    name: '测试商品1',
    price: 99.9,
    imageUrl: '/static/default-product.png'
  },
  {
    id: 2,
    name: '测试商品2',
    price: 199.9,
    imageUrl: '/static/default-product.png'
  },
  {
    id: 3,
    name: '测试商品3',
    price: 299.9,
    imageUrl: '/static/default-product.png'
  }
]);

const addLog = (message) => {
  const timestamp = new Date().toLocaleTimeString();
  logs.value.unshift(`[${timestamp}] ${message}`);
  if (logs.value.length > 10) {
    logs.value = logs.value.slice(0, 10);
  }
};

const goToProductDetail = (product) => {
  addLog(`点击商品卡片，跳转到商品详情: ${product.name} (ID: ${product.id})`);
  uni.navigateTo({
    url: `/pages/productDetail/productDetail?id=${product.id}`
  });
};

const addToCart = (product) => {
  addLog(`点击购买按钮，跳转到商品详情: ${product.name} (ID: ${product.id})`);
  uni.navigateTo({
    url: `/pages/productDetail/productDetail?id=${product.id}`
  });
};

// 页面加载时添加日志
addLog('测试页面已加载');
</script>

<style scoped>
.test-container {
  padding: 40rpx;
  background-color: #f5f5f5;
  min-height: 100vh;
}

.test-header {
  text-align: center;
  margin-bottom: 40rpx;
}

.test-title {
  font-size: 36rpx;
  font-weight: bold;
  color: #333;
}

.test-section {
  background: white;
  border-radius: 16rpx;
  padding: 30rpx;
  margin-bottom: 30rpx;
}

.section-title {
  font-size: 32rpx;
  font-weight: bold;
  color: #333;
  margin-bottom: 20rpx;
  display: block;
}

.test-products {
  display: flex;
  flex-direction: column;
  gap: 20rpx;
}

.test-product-card {
  display: flex;
  background: #f8f8f8;
  border-radius: 12rpx;
  padding: 20rpx;
  cursor: pointer;
}

.test-product-image {
  width: 120rpx;
  height: 120rpx;
  border-radius: 8rpx;
  margin-right: 20rpx;
}

.test-product-info {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.test-product-name {
  font-size: 28rpx;
  font-weight: bold;
  color: #333;
}

.test-product-price {
  font-size: 32rpx;
  color: #ff4444;
  font-weight: bold;
}

.test-buy-btn {
  align-self: flex-end;
  background: linear-gradient(90deg, #4CAF50 60%, #43a047 100%);
  color: white;
  padding: 10rpx 20rpx;
  border-radius: 20rpx;
  font-size: 24rpx;
  box-shadow: 0 2rpx 8rpx rgba(76,175,80,0.08);
  transition: all 0.3s ease;
}

.test-buy-btn:active {
  transform: scale(0.95);
  background: #388e3c;
}

.log-container {
  background: #f8f8f8;
  border-radius: 8rpx;
  padding: 20rpx;
  max-height: 400rpx;
  overflow-y: auto;
}

.log-item {
  font-size: 24rpx;
  color: #666;
  margin-bottom: 10rpx;
  display: block;
  font-family: monospace;
}
</style> 